changeSet.sql:
DO $$
BEGIN
    IF to_regclass('public.private_chat_client_keys') IS NOT NULL
       AND to_regclass('public.public_keys') IS NULL THEN
        ALTER TABLE public.private_chat_client_keys RENAME TO public_keys;
    END IF;
END
$$;

DO $$
BEGIN
    IF to_regclass('public.idx_private_chat_client_keys_user_status_updated') IS NOT NULL
       AND to_regclass('public.idx_public_keys_user_status_updated') IS NULL THEN
        ALTER INDEX public.idx_private_chat_client_keys_user_status_updated
            RENAME TO idx_public_keys_user_status_updated;
    END IF;
END
$$;
